using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// Train the model at startup and save it
var modelPath = Path.Combine(AppContext.BaseDirectory, "ChurnModel.zip");
TrainModel(Path.Combine("Data", "customers.csv"), modelPath);

// Register pooled prediction engine (thread-safe for ASP.NET Core)
builder.Services.AddPredictionEnginePool<ChurnInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with customer data");

app.MapPost("/predict", (ChurnInput input, PredictionEnginePool<ChurnInput, ChurnPrediction> pool) =>
{
    var prediction = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = prediction.PredictedLabel,
        Probability = prediction.Probability,
        Score = prediction.Score,
    });
});

app.Run();

static void TrainModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    var data = mlContext.Data.LoadFromTextFile<ChurnInput>(
        dataPath, hasHeader: true, separatorChar: ',');

    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

    var pipeline = mlContext.Transforms.Categorical
            .OneHotEncoding("RegionEncoded", nameof(ChurnInput.Region))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(ChurnInput.Age),
            nameof(ChurnInput.Income),
            "RegionEncoded",
            nameof(ChurnInput.PurchaseHistory)))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers
            .SdcaLogisticRegression(
                labelColumnName: "Label",
                featureColumnName: "Features"));

    // Map the "Churned" text column to a boolean Label column
    var labelPipeline = mlContext.Transforms.CustomMapping<ChurnInput, ChurnLabel>(
            (input, output) => output.Label = input.Churned == "Yes", contractName: null)
        .Append(pipeline);

    var model = labelPipeline.Fit(split.TrainSet);

    // Evaluate on the test set
    var predictions = model.Transform(split.TestSet);
    try
    {
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);
        Console.WriteLine($"[ML.NET] AUC: {metrics.AreaUnderRocCurve:F4}, " +
                          $"F1: {metrics.F1Score:F4}, " +
                          $"Accuracy: {metrics.Accuracy:F4}");
    }
    catch (ArgumentOutOfRangeException)
    {
        Console.WriteLine("[ML.NET] Warning: Test set too small for full evaluation " +
                          "(needs both positive and negative examples). Add more data.");
    }

    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"[ML.NET] Model saved to {modelPath}");
}

