static void TrainModel(string dataPath, string modelPath)
{
    var mlContext = new MLContext(seed: 42);

    // Load CSV and convert string label to bool before building the IDataView
    var rows = File.ReadAllLines(dataPath)
        .Skip(1)
        .Where(line => !string.IsNullOrWhiteSpace(line))
        .Select(line =>
        {
            var parts = line.Split(',');
            return new ChurnTrainingRow
            {
                Age = float.Parse(parts[0], CultureInfo.InvariantCulture),
                Income = float.Parse(parts[1], CultureInfo.InvariantCulture),
                Region = parts[2].Trim(),
                PurchaseHistory = float.Parse(parts[3], CultureInfo.InvariantCulture),
                Label = parts[4].Trim().Equals("Yes", StringComparison.OrdinalIgnoreCase),
            };
        })
        .ToList();

    var data = mlContext.Data.LoadFromEnumerable(rows);
    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2);

    var pipeline = mlContext.Transforms.Categorical
            .OneHotEncoding("RegionEncoded", nameof(ChurnTrainingRow.Region))
        .Append(mlContext.Transforms.Concatenate("Features",
            nameof(ChurnTrainingRow.Age),
            nameof(ChurnTrainingRow.Income),
            "RegionEncoded",
            nameof(ChurnTrainingRow.PurchaseHistory)))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.BinaryClassification.Trainers
            .SdcaLogisticRegression(
                labelColumnName: "Label",
                featureColumnName: "Features"));

    var model = pipeline.Fit(split.TrainSet);

    // Evaluate on the test set
    var predictions = model.Transform(split.TestSet);
    try
    {
        var metrics = mlContext.BinaryClassification.Evaluate(predictions);
        Console.WriteLine($"[ML.NET] AUC: {metrics.AreaUnderRocCurve:F4}, " +
                          $"F1: {metrics.F1Score:F4}, " +
                          $"Accuracy: {metrics.Accuracy:F4}");
    }
    catch (ArgumentOutOfRangeException)
    {
        Console.WriteLine("[ML.NET] Warning: Test set too small for full evaluation " +
                          "(needs both positive and negative examples). Add more data.");
    }

    mlContext.Model.Save(model, data.Schema, modelPath);
    Console.WriteLine($"[ML.NET] Model saved to {modelPath}");
}

